  display: flex;
  gap: 10px;
  margin-bottom: 15px;
  padding-bottom: 15px;
  border-bottom: 1px solid #eee;
}

.nav-bar button {
  padding: 8px 16px;
  cursor: pointer;
  border: 1px solid #ccc;
  background: white;
  border-radius: 4px;
}

.nav-bar button:hover {
  background: #f0f0f0;
}

/* REPL - Separate Screen */
#repl-container {
