  flex-direction: column;
  flex: 1;
  min-height: 0;
  overflow: hidden;
}

.repl-input-scroll {
  flex: 1;
  overflow-y: auto;
  padding: 20px;
}

#repl-input {
  width: 100%;
  height: 100%;
