export async function render(item, api) {
  const container = api.createElement('div', {
    style: 'display: flex; flex-direction: column; gap: 16px; min-width: 500px;'
  }, []);

  // JSON textarea
  const textarea = api.createElement('textarea', {
    style: 'width: 100%; height: 400px; font-family: monospace; font-size: 13px; padding: 12px; border: 1px solid #ccc; border-radius: 4px; resize: vertical;',
    spellcheck: 'false'
  }, []);
  textarea.value = JSON.stringify(item, null, 2);
  container.appendChild(textarea);

  // Error message area
  const errorArea = api.createElement('div', {
    style: 'color: #c00; font-size: 13px; min-height: 20px;'
  }, []);
  container.appendChild(errorArea);

  // Button row
  const buttonRow = api.createElement('div', {
    style: 'display: flex; gap: 10px; justify-content: flex-end;'
  }, []);

  // Cancel button
  const cancelBtn = api.createElement('button', {
    style: 'padding: 8px 16px; cursor: pointer;',
    onclick: () => api.close()
  }, ['Cancel']);
  buttonRow.appendChild(cancelBtn);

  // Save button
  const saveBtn = api.createElement('button', {
    style: 'padding: 8px 16px; cursor: pointer; background: #007bff; color: white; border: none; border-radius: 4px;',
    onclick: async () => {
      try {
        const parsed = JSON.parse(textarea.value);
        // Preserve the original ID - prevent accidental ID changes
        parsed.id = item.id;
        await api.saveAndClose(parsed);
      } catch (e) {
        errorArea.textContent = 'Invalid JSON: ' + e.message;
      }
    }
  }, ['Save']);
  buttonRow.appendChild(saveBtn);

  container.appendChild(buttonRow);

  // Keyboard shortcut: Ctrl/Cmd+S to save
  textarea.addEventListener('keydown', async (e) => {
    if ((e.ctrlKey || e.metaKey) && e.key === 's') {
      e.preventDefault();
      try {
        const parsed = JSON.parse(textarea.value);
        parsed.id = item.id;
        await api.saveAndClose(parsed);
      } catch (err) {
        errorArea.textContent = 'Invalid JSON: ' + err.message;
      }
    }
  });

  return container;
}

export async function render(item, api) {
  // Load CSS
  const cssLoader = await api.require('css-loader-lib');
  await cssLoader.loadCSS('codemirror-css', api);

  // Load shared libraries
  const treeBuilder = await api.require('tag-tree-builder');
  const tagPickerUI = await api.require('tag-picker-ui');

  // Helper: Extract transclusion IDs from markdown (with fragments and query params)
  const extractTransclusionIds = (markdown) => {
    const transclusionPattern = /!\[([^\]]*)\]\(item:\/\/([a-f0-9\-]+)(?:[#?][^)]*)?\)/gi;
    const ids = new Set();
    let match;
    while ((match = transclusionPattern.exec(markdown)) !== null) {
      ids.add(match[2]); // Capture group 2 is the item ID (without fragment/query)
    }
    return Array.from(ids);
  };

  // Helper: Parse item URL to extract ID, fragment, and query params
  const parseItemUrl = (url) => {
    // URL format: item://id#fragment?query=params
    const match = url.match(/item:\/\/([a-f0-9\-]+)(?:#([^?]+))?(?:\?(.+))?/);
    if (!match) return null;

    const itemId = match[1];
    const fragment = match[2] || null;
    const queryString = match[3] || null;

    const queryParams = {};
    if (queryString) {
      queryString.split('&').forEach(pair => {
        const [key, value] = pair.split('=');
        queryParams[key] = value;
      });
    }

    return { itemId, fragment, queryParams };
  };

  // Helper: Extract field value from item
  const getFieldValue = (item, fieldName) => {
    if (fieldName === 'name') return item.name || '';
    if (fieldName === 'content') return JSON.stringify(item.content, null, 2);
    return item.content?.[fieldName] || '';
  };

  // Helper: Extract region between comment markers
  const extractRegion = (text, regionName) => {
    const lines = text.split('\n');
    const beginMarker = '[BEGIN:' + regionName + ']';
    const endMarker = '[END:' + regionName + ']';

    let beginIdx = -1;
    let endIdx = -1;

    // Find markers (case-insensitive, trim whitespace and comments)
    for (let i = 0; i < lines.length; i++) {
      const trimmed = lines[i].trim();
      // Remove common comment prefixes: //, #, <!--, etc.
      const cleaned = trimmed.replace(/^\/\/\s*/, '').replace(/^#\s*/, '').replace(/^<!--\s*/, '').replace(/\s*-->$/, '').trim();

      if (cleaned === beginMarker) {
        beginIdx = i;
      } else if (cleaned === endMarker && beginIdx >= 0) {
        endIdx = i;
        break;
      }
    }

    if (beginIdx === -1 || endIdx === -1) {
      throw new Error('Region markers not found: ' + regionName);
    }

    if (endIdx <= beginIdx) {
      throw new Error('Invalid region: END marker before BEGIN');
    }

    // Extract lines between markers (exclusive)
    const extractedLines = lines.slice(beginIdx + 1, endIdx);

    return {
      text: extractedLines.join('\n'),
      startLine: beginIdx + 2 // +1 for 0->1 indexing, +1 to skip BEGIN marker
    };
  };

  // Helper: Apply line range to text
  const applyLineRange = (text, linesParam, baseStartLine = 1) => {
    if (!linesParam) return { text, startLine: baseStartLine };

    const lines = text.split('\n');
    let startLine, endLine;

    if (linesParam.includes('-')) {
      const parts = linesParam.split('-');
      startLine = parts[0] ? parseInt(parts[0]) : 1;
      endLine = parts[1] ? parseInt(parts[1]) : lines.length;
    } else {
      startLine = endLine = parseInt(linesParam);
    }

    // Adjust to 0-based indexing
    const start = Math.max(0, startLine - 1);
    const end = Math.min(lines.length, endLine);

    return {
      text: lines.slice(start, end).join('\n'),
      startLine: baseStartLine + start
    };
  };
  // Check if this item is the viewport root
  const viewportRootId = new URLSearchParams(window.location.search).get('root');
  const isViewportRoot = item.id === viewportRootId;


  const container = api.createElement('div', {
    class: 'note-view',
    style: 'height: 100%; display: flex; flex-direction: column; max-width: 800px; margin: 0 auto;'
  }, []);

  // Header section
  const header = api.createElement('div', {
    style: 'margin-bottom: 20px; padding-bottom: 15px; border-bottom: 2px solid #e0e0e0; flex-shrink: 0;'
  }, []);

  // Title (editable)
  const titleInput = api.createElement('input', {
    type: 'text',
    value: item.name || '',
    placeholder: 'Untitled Note',
    style: 'width: 100%; font-size: 24px; font-weight: bold; border: none; outline: none; padding: 8px 0; background: transparent;',
    onchange: async (e) => {
      const updated = {
        ...item,
        name: e.target.value
      };
      await api.update(updated);
      item = await api.get(item.id);
    }
  }, []);
  header.appendChild(titleInput);

  // Tags section - this will be updated by renderTags()
  const tagsContainer = api.createElement('div', {
    style: 'margin-top: 12px;'
  }, []);
  header.appendChild(tagsContainer);

  // Metadata
  const meta = api.createElement('div', {
    style: 'margin-top: 8px; font-size: 12px; color: #999;'
  }, [
    'Modified: ' + new Date(item.modified).toLocaleString()
  ]);
  header.appendChild(meta);

  container.appendChild(header);

  // Body section with view/edit toggle
  let isEditing = false;
  let codeMirrorInstance = null;

  // Scrollable content area (flex: 1)
  const scrollableContent = api.createElement('div', {
    style: 'flex: 1; overflow-y: auto; min-height: 0;'
  }, []);

  // Button bar at bottom (flex-shrink: 0)
  const buttonBar = api.createElement('div', {
    style: 'margin-top: 15px; display: flex; gap: 10px; flex-wrap: wrap; flex-shrink: 0;'
  }, []);

  // Pending tags (buffered changes, not yet saved)
  let pendingTags = null;

  // Track picker open state across re-renders
  let isPickerOpen = false;

  // Helper function to build tag path
  const getTagPath = async (tag) => {
    const path = [];
    let currentTag = tag;

    while (currentTag) {
      const tagName = currentTag.content.name || currentTag.name || currentTag.id;
      path.unshift(tagName);

      if (currentTag.content.parent) {
        try {
          currentTag = await api.get(currentTag.content.parent);
        } catch (err) {
          break;
        }
      } else {
        break;
      }
    }

    return path.join(' / ');
  };

  // Save pending tags to database
  const saveTags = async () => {
    if (pendingTags === null) return;

    const updated = {
      ...item,
      tags: pendingTags
    };
    await api.update(updated);
    item = await api.get(item.id);
    pendingTags = null;
  };

  // Track expanded state (shared across re-renders)
  const expandedState = new Map();

  // Function to render tags (called in both modes)
  const renderTags = async (editMode) => {
    tagsContainer.innerHTML = '';

    if (editMode) {
      // Initialize pending tags on first render in edit mode
      if (pendingTags === null) {
        pendingTags = [...(item.tags || [])];
      }

      // Edit mode: pills with remove buttons + add button + picker
      const tagsLabel = api.createElement('div', {
        style: 'font-size: 13px; color: #666; font-weight: 500; margin-bottom: 6px;'
      }, ['Tags:']);
      tagsContainer.appendChild(tagsLabel);

      const tagPillsAndButtons = api.createElement('div', {
        style: 'display: flex; flex-wrap: wrap; gap: 6px; align-items: center;'
      }, []);

      // Render current tags as removable pills (using pendingTags)
      if (pendingTags.length > 0) {
        for (const tagId of pendingTags) {
          try {
            const tag = await api.get(tagId);
            const tagPath = await getTagPath(tag);
            const tagColor = tag.content.color || '#3b82f6';

            const pill = api.createElement('span', {
              style: 'display: inline-flex; align-items: center; gap: 6px; padding: 4px 8px 4px 12px; background: ' + tagColor + '20; border: 1px solid ' + tagColor + '; border-radius: 12px; font-size: 12px; font-weight: 500; color: ' + tagColor + ';'
            }, []);

            const pillText = api.createElement('span', {}, [tagPath]);
            pill.appendChild(pillText);

            // Remove button
            const removeBtn = api.createElement('button', {
              style: 'background: none; border: none; color: ' + tagColor + '; cursor: pointer; padding: 0; margin: 0; font-size: 14px; line-height: 1; font-weight: bold;',
              onclick: async () => {
                pendingTags = pendingTags.filter(id => id !== tagId);
                await renderTags(true);
              }
            }, ['×']);
            pill.appendChild(removeBtn);

            tagPillsAndButtons.appendChild(pill);
          } catch (err) {
            const pill = api.createElement('span', {
              style: 'display: inline-flex; align-items: center; gap: 6px; padding: 4px 8px 4px 12px; background: #fee; border: 1px solid #f88; border-radius: 12px; font-size: 12px; font-weight: 500; color: #c44; font-family: monospace;',
              title: 'Tag not found: ' + tagId
            }, [tagId.substring(0, 8) + '...']);

            tagPillsAndButtons.appendChild(pill);
          }
        }
      }

      // Add Tag button
      const addTagBtn = api.createElement('button', {
        style: 'padding: 4px 12px; background: #3b82f6; color: white; border: none; border-radius: 12px; font-size: 12px; font-weight: 500; cursor: pointer;',
        onclick: () => {
          toggleTagPicker();
        }
      }, ['+ Add Tag']);
      tagPillsAndButtons.appendChild(addTagBtn);

      tagsContainer.appendChild(tagPillsAndButtons);

      // Tag picker panel
      const pickerPanel = api.createElement('div', {
        style: (isPickerOpen ? 'display: block;' : 'display: none;') + ' margin-top: 12px; padding: 15px; background: #f9f9f9; border: 1px solid #d0d0d0; border-radius: 6px; max-height: 400px; overflow-y: auto;'
      }, []);

      const pickerHeader = api.createElement('div', {
        style: 'display: flex; justify-content: space-between; align-items: center; margin-bottom: 12px;'
      }, []);

      const pickerTitle = api.createElement('div', {
        style: 'font-weight: 500; color: #333;'
      }, ['Select tags']);
      pickerHeader.appendChild(pickerTitle);

      const closePickerBtn = api.createElement('button', {
        style: 'background: none; border: none; font-size: 18px; cursor: pointer; color: #666;',
        onclick: async () => {
          await saveTags();
          isPickerOpen = false;
          await renderTags(true);
        }
      }, ['×']);
      pickerHeader.appendChild(closePickerBtn);

      pickerPanel.appendChild(pickerHeader);

      const pickerTreeContainer = api.createElement('div', {}, []);
      pickerPanel.appendChild(pickerTreeContainer);

      tagsContainer.appendChild(pickerPanel);

      // Toggle picker visibility and load tags
      const toggleTagPicker = async () => {
        if (!isPickerOpen) {
          isPickerOpen = true;
          await renderTags(true);
        } else {
          await saveTags();
          isPickerOpen = false;
          await renderTags(true);
        }
      };

      // If picker is open, render the tree
      if (isPickerOpen) {
        await renderTagPicker();
      }

      // Render tag picker tree
      async function renderTagPicker() {
        pickerTreeContainer.innerHTML = '';
        const allTags = await api.query({ type: "d1da8525-b0dc-4a79-8bef-0cbed1ed003d" });
        const tree = treeBuilder.buildTagTree(allTags);

        tagPickerUI.renderTagPicker({
          container: pickerTreeContainer,
          tree: tree,
          selectedTags: pendingTags,
          expandedState: expandedState,
          onToggle: async (tagId) => {
            pendingTags.push(tagId);
            await renderTagPicker();
          },
          onExpand: async () => {
            await renderTagPicker();
          }
        }, api);
      }

    } else {
      // View mode: display tag names as pills with full paths
      if (item.tags && item.tags.length > 0) {
        const tagsLabel = api.createElement('div', {
          style: 'font-size: 13px; color: #666; font-weight: 500; margin-bottom: 6px;'
        }, ['Tags:']);
        tagsContainer.appendChild(tagsLabel);

        const tagPills = api.createElement('div', {
          style: 'display: flex; flex-wrap: wrap; gap: 6px;'
        }, []);

        for (const tagId of item.tags) {
          try {
            const tag = await api.get(tagId);
            const tagPath = await getTagPath(tag);
            const tagColor = tag.content.color || '#3b82f6';

            const pill = api.createElement('span', {
              style: 'display: inline-block; padding: 4px 12px; background: ' + tagColor + '20; border: 1px solid ' + tagColor + '; border-radius: 12px; font-size: 12px; font-weight: 500; color: ' + tagColor + ';'
            }, [tagPath]);

            tagPills.appendChild(pill);
          } catch (err) {
            const pill = api.createElement('span', {
              style: 'display: inline-block; padding: 4px 12px; background: #fee; border: 1px solid #f88; border-radius: 12px; font-size: 12px; font-weight: 500; color: #c44; font-family: monospace;',
              title: 'Tag not found: ' + tagId
            }, [tagId.substring(0, 8) + '...']);

            tagPills.appendChild(pill);
          }
        }

        tagsContainer.appendChild(tagPills);
      }
    }
  };

  const renderBody = async () => {
    scrollableContent.innerHTML = '';
    buttonBar.innerHTML = '';

    if (isEditing) {
      // Edit mode: CodeMirror editor

      await api.require('codemirror');           // Sets window.CodeMirror                                        
      await api.require('codemirror-markdown');  // Extends window.CodeMirror                                     
      const CM = window.CodeMirror;              // Grab it                                                       
      //delete window.CodeMirror;                  // Clean up global                                               
      const CodeMirror = CM;                     // Use local reference   

      const editorContainer = api.createElement('div', {
        style: 'border: 1px solid #d0d0d0; border-radius: 6px; overflow: hidden; height: 100%;'
      }, []);
      scrollableContent.appendChild(editorContainer);

      codeMirrorInstance = CodeMirror(editorContainer, {
        value: item.content.description || '',
        mode: 'markdown',
        lineNumbers: true,
        lineWrapping: true,
        theme: 'default',
        viewportMargin: 2000,
        extraKeys: {
          'Tab': (cm) => {
            cm.replaceSelection('  ');
          }
        }
      });

      // Make editor fill container                                                                             
      codeMirrorInstance.setSize('100%', '100%');  

      // Buttons - append directly to buttonBar

      const saveBtn = api.createElement('button', {
        style: 'padding: 10px 20px; cursor: pointer; font-weight: 500;',
        onclick: async () => {
          await saveTags();

          const markdownContent = codeMirrorInstance.getValue();

          // Extract transclusion IDs and add them as children
          const transclusionIds = extractTransclusionIds(markdownContent);
          for (const transclusionId of transclusionIds) {
            try {
              await api.addChild(transclusionId);
            } catch (err) {
              console.warn('Failed to add transcluded item as child:', transclusionId, err);
            }
          }

          const updated = {
            ...item,
            content: {
              ...item.content,
              description: markdownContent
            }
          };
          await api.update(updated);
          item = await api.get(item.id);
          isEditing = false;
          isPickerOpen = false;
          pendingTags = null;
          codeMirrorInstance = null;
          await renderTags(false);
          await renderBody();
        }
      }, ['Save']);
      buttonBar.appendChild(saveBtn);

      const cancelBtn = api.createElement('button', {
        style: 'padding: 10px 20px; cursor: pointer;',
        onclick: async () => {
          isEditing = false;
          isPickerOpen = false;
          pendingTags = null;
          codeMirrorInstance = null;
          item = await api.get(item.id);
          await renderTags(false);
          await renderBody();
        }
      }, ['Cancel']);
      buttonBar.appendChild(cancelBtn);

      const insertBtn = api.createElement('button', {
        style: 'padding: 10px 20px; cursor: pointer; background: #28a745; color: white; border: none; border-radius: 4px;',
        onclick: () => showItemPicker()
      }, ['Insert Link/Transclusion']);
      buttonBar.appendChild(insertBtn);



      // Item picker UI
      const pickerContainer = api.createElement('div', {
        style: 'display: none; margin-top: 15px; padding: 15px; border: 1px solid #ddd; border-radius: 6px; background: #f9f9f9;'
      }, []);
      scrollableContent.appendChild(pickerContainer);

      const showItemPicker = async () => {
        pickerContainer.innerHTML = '';
        pickerContainer.style.display = 'block';

        const pickerHeader = api.createElement('div', {
          style: 'display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px;'
        }, []);

        const pickerTitle = api.createElement('h4', {
          style: 'margin: 0;'
        }, ['Insert Link or Transclusion']);
        pickerHeader.appendChild(pickerTitle);

        const pickerClose = api.createElement('button', {
          style: 'padding: 6px 12px; cursor: pointer; background: #f0f0f0; border: 1px solid #ccc; border-radius: 4px;',
          onclick: () => {
            pickerContainer.style.display = 'none';
            pickerContainer.innerHTML = '';
          }
        }, ['Close']);
        pickerHeader.appendChild(pickerClose);

        pickerContainer.appendChild(pickerHeader);

        const searchContainer = api.createElement('div', {}, []);
        pickerContainer.appendChild(searchContainer);

        const searchLib = await api.require('item-search-lib');

        const insertReference = (targetItem, asTransclusion) => {
          const targetName = targetItem.name || targetItem.id;
          const prefix = asTransclusion ? '!' : '';
          const refText = prefix + '[' + targetName + '](item://' + targetItem.id + ')';
          codeMirrorInstance.replaceSelection(refText);
          pickerContainer.style.display = 'none';
          pickerContainer.innerHTML = '';
          codeMirrorInstance.focus();
        };

        // Custom callback that shows link/transclude buttons
        const onSelectCallback = (targetItem) => {
          // Clear previous selection if any
          const existing = searchContainer.querySelector('.item-action-buttons');
          if (existing) existing.remove();

          const actionButtons = api.createElement('div', {
            class: 'item-action-buttons',
            style: 'margin-top: 15px; padding: 15px; background: #fff; border: 1px solid #ddd; border-radius: 4px; display: flex; gap: 10px; align-items: center;'
          }, []);

          const selectedLabel = api.createElement('div', {
            style: 'flex: 1; font-weight: 500;'
          }, ['Selected: ' + (targetItem.name || targetItem.id)]);
          actionButtons.appendChild(selectedLabel);

          const linkBtn = api.createElement('button', {
            style: 'padding: 8px 16px; cursor: pointer; background: #007bff; color: white; border: none; border-radius: 4px;',
            onclick: () => insertReference(targetItem, false)
          }, ['Insert Link']);
          actionButtons.appendChild(linkBtn);

          const transcludeBtn = api.createElement('button', {
            style: 'padding: 8px 16px; cursor: pointer; background: #28a745; color: white; border: none; border-radius: 4px;',
            onclick: () => insertReference(targetItem, true)
          }, ['Insert Transclusion']);
          actionButtons.appendChild(transcludeBtn);

          searchContainer.appendChild(actionButtons);
        };

        searchLib.createSearchUI(
          searchContainer,
          onSelectCallback,
          api,
          {
            placeholder: 'Search items...',
            autoFocus: true
          }
        );
      };

      await renderTags(true);

    } else {
      // View mode: markdown-it rendering
      await api.require('markdown-it');
      const markdownitModule = await api.require('markdown-it-wrapper');                                          
      const markdownit = markdownitModule.default;

      // Configure markdown-it to handle item:// links
      const renderer = markdownit.renderer;
      const defaultLinkRender = renderer.rules.link_open || function(tokens, idx, options, env, self) {
        return self.renderToken(tokens, idx, options);
      };

      renderer.rules.link_open = function(tokens, idx, options, env, self) {
        const token = tokens[idx];
        const hrefIndex = token.attrIndex('href');

        if (hrefIndex >= 0) {
          const href = token.attrs[hrefIndex][1];
          if (href.startsWith('item://')) {
            // Mark as item link
            token.attrSet('data-item-link', href);
            token.attrSet('href', '#');
          }
        }

        return defaultLinkRender(tokens, idx, options, env, self);
      };

      const body = item.content.description || '*No content yet. Click Edit to add some.*';
      const html = markdownit.render(body);

      const content = api.createElement('div', {
        class: 'markdown-content',
        style: 'line-height: 1.8; font-size: 16px;'
      }, []);
      content.innerHTML = html;

      // Handle item:// link clicks
      const links = content.querySelectorAll('a[data-item-link]');
      links.forEach(link => {
        const href = link.getAttribute('data-item-link');
        const itemId = href.replace('item://', '');
        link.onclick = (e) => {
          e.preventDefault();
          api.openSibling(itemId);
        };
        link.style.color = '#007bff';
        link.style.textDecoration = 'none';
        link.style.borderBottom = '1px solid #007bff';
        link.style.cursor = 'pointer';
      });

      // Handle transclusions: Find img tags with item:// src
      // Markdown-it converts ![alt](item://id) to <img src="item://id" alt="alt">
      const transclusionImages = content.querySelectorAll('img[src^="item://"]');

      for (const img of transclusionImages) {
        const fullUrl = img.src.replace(/^.*item:\/\//, 'item://');
        const parsed = parseItemUrl(fullUrl);
        const altText = img.alt;

        if (!parsed) {
          // Invalid URL format
          const errorDiv = api.createElement('div', {
            class: 'transclusion-missing',
            style: 'background: #fff3cd; border: 1px solid #ffc107; border-radius: 4px; padding: 8px 12px; margin: 10px 0; color: #856404; font-style: italic;'
          }, ['[Invalid URL: ' + altText + ']']);
          img.parentNode.replaceChild(errorDiv, img);
          continue;
        }

        try {
          const transcludedItem = await api.get(parsed.itemId);

          // Check if this is a partial transclusion (has fragment or query params)
          const isPartial = parsed.fragment || Object.keys(parsed.queryParams).length > 0;

          if (isPartial) {
            // Partial transclusion: extract field and apply region/line range
            const fieldName = parsed.fragment || 'content';
            let fieldValue = getFieldValue(transcludedItem, fieldName);

            if (!fieldValue) {
              throw new Error('Field not found: ' + fieldName);
            }

            let text;
            let startLine = 1;

            // First, apply region extraction if specified
            if (parsed.queryParams.region) {
              const regionResult = extractRegion(fieldValue, parsed.queryParams.region);
              text = regionResult.text;
              startLine = regionResult.startLine;
            } else {
              text = fieldValue;
            }

            // Then, optionally apply line range filtering
            if (parsed.queryParams.lines) {
              const rangeResult = applyLineRange(text, parsed.queryParams.lines, startLine);
              text = rangeResult.text;
              startLine = rangeResult.startLine;
            }

            // Create wrapper container
            const wrapper = api.createElement('div', {
              class: 'transclusion-container partial',
              style: 'background: #f9f9f9; border: 1px solid #e0e0e0; border-radius: 6px; padding: 15px; margin: 15px 0;'
            }, []);

            // Build header description
            let headerDesc = transcludedItem.name || transcludedItem.id;
            if (parsed.fragment) {
              headerDesc += ' (#' + parsed.fragment;
              if (parsed.queryParams.region) {
                headerDesc += ', region=' + parsed.queryParams.region;
              }
              if (parsed.queryParams.lines) {
                headerDesc += ', lines=' + parsed.queryParams.lines;
              }
              headerDesc += ')';
            }

            // Header (clickable to navigate)
            const header = api.createElement('div', {
              style: 'font-size: 12px; color: #666; margin-bottom: 10px; padding-bottom: 8px; border-bottom: 1px solid #ddd; cursor: pointer;',
              onclick: () => { const navFn = isViewportRoot ? api.navigate : api.openSibling; navFn(parsed.itemId); }
            }, ['Transcluded from: ' + headerDesc]);
            wrapper.appendChild(header);

            // Content as <pre><code> with line numbers
            const pre = api.createElement('pre', {
              style: 'margin: 0; padding: 10px; background: #fff; border-radius: 4px; overflow-x: auto; font-family: monospace; font-size: 13px; line-height: 1.5;'
            }, []);

            const code = api.createElement('code', {}, []);

            // Add line numbers and content
            const lines = text.split('\n');
            lines.forEach((line, idx) => {
              const lineNum = startLine + idx;
              const lineNumSpan = api.createElement('span', {
                style: 'display: inline-block; width: 40px; color: #999; user-select: none; text-align: right; margin-right: 10px;'
              }, [lineNum + '']);

              const lineContent = api.createElement('span', {}, [line]);

              code.appendChild(lineNumSpan);
              code.appendChild(lineContent);
              if (idx < lines.length - 1) {
                code.appendChild(document.createTextNode('\n'));
              }
            });

            pre.appendChild(code);
            wrapper.appendChild(pre);

            // Replace the img tag with the wrapper
            img.parentNode.replaceChild(wrapper, img);

          } else {
            // Full transclusion: render entire item
            const renderedContent = await api.renderItem(parsed.itemId);

            // Create wrapper container
            const wrapper = api.createElement('div', {
              class: 'transclusion-container',
              style: 'background: #f9f9f9; border: 1px solid #e0e0e0; border-radius: 6px; padding: 15px; margin: 15px 0;'
            }, []);

            // Header (clickable to navigate)
            const header = api.createElement('div', {
              style: 'font-size: 12px; color: #666; margin-bottom: 10px; padding-bottom: 8px; border-bottom: 1px solid #ddd; cursor: pointer;',
              onclick: () => { const navFn = isViewportRoot ? api.navigate : api.openSibling; navFn(parsed.itemId); }
            }, ['Transcluded from: ' + (transcludedItem.name || transcludedItem.id)]);
            wrapper.appendChild(header);

            // Rendered content
            wrapper.appendChild(renderedContent);

            // Replace the img tag with the wrapper
            img.parentNode.replaceChild(wrapper, img);
          }
        } catch (err) {
          // Item not found or rendering failed
          const errorDiv = api.createElement('div', {
            class: 'transclusion-missing',
            style: 'background: #fff3cd; border: 1px solid #ffc107; border-radius: 4px; padding: 8px 12px; margin: 10px 0; color: #856404; font-style: italic;'
          }, ['[Missing: ' + altText + ' - ' + err.message + ']']);

          img.parentNode.replaceChild(errorDiv, img);
        }
      }

      scrollableContent.appendChild(content);

      const editBtn = api.createElement('button', {
        style: 'padding: 10px 20px; cursor: pointer;',
        onclick: () => {
          isEditing = true;
          renderBody();
        }
      }, ['Edit']);
      buttonBar.appendChild(editBtn);

      await renderTags(false);
    }
  };

  await renderBody();
  container.appendChild(scrollableContent);
  container.appendChild(buttonBar);

  return container;
}

/**
 * Search items based on query string
 */
export async function searchItems(query, api, options = {}) {
  if (!query || query.trim().length === 0) {
    return [];
  }

  const { targetContainer, allItems } = options;
  let itemsToSearch;

  if (allItems) {
    itemsToSearch = allItems;
  } else if (targetContainer) {
    try {
      const container = await api.get(targetContainer);
      const childIds = (container.children || []).map(c =>
        typeof c === 'string' ? c : c.id
      );
      itemsToSearch = await Promise.all(
        childIds.map(id => api.get(id).catch(() => null))
      );
      itemsToSearch = itemsToSearch.filter(i => i !== null);
    } catch (err) {
      console.error('Error fetching container:', err);
      itemsToSearch = [];
    }
  } else {
    itemsToSearch = await api.getAll();
  }

  const queryLower = query.toLowerCase();
  const matches = itemsToSearch.filter(item => {
    const searchableText = [
      item.name,
      item.content?.title,
      item.content?.body,
      item.content?.description,
      JSON.stringify(item.content)
    ].filter(Boolean).join(' ').toLowerCase();

    return searchableText.includes(queryLower);
  });

  matches.sort((a, b) => a.name.localeCompare(b.name));
  return matches;
}

/**
 * Create a search UI widget
 */
export function createSearchUI(containerEl, onSelect, api, options = {}) {
  const {
    placeholder = 'Search for items...',
    savedQuery = '',
    targetContainer = null,
    autoFocus = false
  } = options;

  containerEl.innerHTML = '';

  const searchBox = api.createElement('div', {
    style: 'margin-bottom: 20px;'
  }, []);

  const input = api.createElement('input', {
    type: 'text',
    placeholder,
    value: savedQuery,
    style: 'width: 100%; padding: 12px 16px; font-size: 16px; border: 2px solid #d0d0d0; border-radius: 8px; outline: none; transition: border-color 0.2s;'
  }, []);

  input.onfocus = () => { input.style.borderColor = '#3b82f6'; };
  input.onblur = () => { input.style.borderColor = '#d0d0d0'; };

  searchBox.appendChild(input);
  containerEl.appendChild(searchBox);

  const resultsContainer = api.createElement('div', {}, []);
  containerEl.appendChild(resultsContainer);

  const statusDiv = api.createElement('div', {
    style: 'padding: 40px; text-align: center; color: #999; font-style: italic;'
  }, ['Type to search...']);
  resultsContainer.appendChild(statusDiv);

  const resultsList = api.createElement('div', {
    style: 'display: none; max-height: 600px; overflow-y: auto;'
  }, []);
  resultsContainer.appendChild(resultsList);

  let searchTimeout = null;
  let currentQuery = savedQuery;

  const executeSearch = async (query) => {
    currentQuery = query;

    if (!query || query.trim().length === 0) {
      statusDiv.style.display = 'block';
      resultsList.style.display = 'none';
      statusDiv.textContent = 'Type to search...';
      return;
    }

    statusDiv.style.display = 'block';
    resultsList.style.display = 'none';
    statusDiv.textContent = 'Searching...';

    const matches = await searchItems(query, api, { targetContainer });

    if (matches.length === 0) {
      statusDiv.style.display = 'block';
      resultsList.style.display = 'none';
      statusDiv.innerHTML = '';

      // Message
      const noMatchMsg = api.createElement('div', {
        style: 'margin-bottom: 16px;'
      }, ['No items found matching "' + query + '"']);
      statusDiv.appendChild(noMatchMsg);

      // Create New button
      const createBtn = api.createElement('button', {
        style: 'padding: 10px 20px; background: #3b82f6; color: white; border: none; border-radius: 6px; cursor: pointer; font-size: 14px; font-weight: 500; transition: background 0.2s;',
        onclick: async () => {
          try {
            // Look up note type
            const noteTypes = await api.query({ name: 'note' });
            const noteTypeId = noteTypes[0]?.id || '871ae771-b9b1-4f40-8c7f-d9038bfb69c3';

            // Create sanitized name (lowercase, underscores for spaces)
            const sanitizedName = query.toLowerCase().replace(/\s+/g, '_');

            // Create new note item
            const newItem = {
              id: crypto.randomUUID(),
              name: sanitizedName,
              type: noteTypeId,
              created: Date.now(),
              modified: Date.now(),
              children: [],
              content: {
                title: query,
                description: ''
              }
            };

            // Save and select
            await api.set(newItem);
            onSelect(newItem);
          } catch (err) {
            console.error('Failed to create item:', err);
            alert('Failed to create item: ' + err.message);
          }
        }
      }, ['Create New: ' + query]);

      // Hover effects
      createBtn.onmouseover = () => {
        createBtn.style.background = '#2563eb';
      };
      createBtn.onmouseout = () => {
        createBtn.style.background = '#3b82f6';
      };

      statusDiv.appendChild(createBtn);
    } else {
      statusDiv.style.display = 'none';
      resultsList.style.display = 'block';
      resultsList.innerHTML = '';

      const countHeader = api.createElement('div', {
        style: 'margin-bottom: 15px; font-size: 14px; color: #666; font-weight: 500;'
      }, ['Found ' + matches.length + ' item' + (matches.length === 1 ? '' : 's')]);
      resultsList.appendChild(countHeader);

      matches.forEach(item => {
        const resultDiv = api.createElement('div', {
          style: 'padding: 12px; margin-bottom: 8px; background: white; border: 1px solid #ddd; border-radius: 6px; cursor: pointer; transition: all 0.2s;'
        }, []);

        const itemTitle = api.createElement('div', {
          style: 'font-weight: 500; color: #333; margin-bottom: 6px; font-size: 15px;'
        }, [item.name || item.content?.title || item.id]);
        resultDiv.appendChild(itemTitle);

        const previewText = item.content?.body || item.content?.description ||
                           JSON.stringify(item.content).substring(0, 150);
        const preview = api.createElement('div', {
          style: 'font-size: 13px; color: #666; margin-bottom: 6px; line-height: 1.4; overflow: hidden; text-overflow: ellipsis; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical;'
        }, [previewText.substring(0, 200)]);
        resultDiv.appendChild(preview);

        const meta = api.createElement('div', {
          style: 'font-size: 12px; color: #999;'
        }, [
          'Type: ' + item.type.substring(0, 8) + '... | Modified: ' +
          new Date(item.modified).toLocaleDateString()
        ]);
        resultDiv.appendChild(meta);

        resultDiv.onclick = () => { onSelect(item); };

        resultDiv.onmouseover = () => {
          resultDiv.style.background = '#f8f9fa';
          resultDiv.style.borderColor = '#3b82f6';
          resultDiv.style.transform = 'translateX(4px)';
        };
        resultDiv.onmouseout = () => {
          resultDiv.style.background = 'white';
          resultDiv.style.borderColor = '#ddd';
          resultDiv.style.transform = 'translateX(0)';
        };

        resultsList.appendChild(resultDiv);
      });
    }
  };

  const performSearch = (query) => {
    if (searchTimeout) {
      clearTimeout(searchTimeout);
    }
    searchTimeout = setTimeout(() => {
      executeSearch(query);
    }, 300);
  };

  input.oninput = (e) => {
    performSearch(e.target.value);
  };

  if (autoFocus) {
    setTimeout(() => input.focus(), 0);
  }

  if (savedQuery && savedQuery.trim().length > 0) {
    executeSearch(savedQuery);
  }

  return {
    performSearch: executeSearch,
    getQuery: () => currentQuery,
    setQuery: (query) => {
      input.value = query;
      executeSearch(query);
    },
    destroy: () => {
      if (searchTimeout) {
        clearTimeout(searchTimeout);
      }
      containerEl.innerHTML = '';
    }
  };
}

export function render(value, onChange, api, options = {}) {
  const textarea = document.createElement('textarea');
  textarea.value = value || '';
  textarea.placeholder = options.placeholder || '';
  textarea.rows = options.rows || 4;
  textarea.style.cssText = 'width: 100%; padding: 8px; border: 1px solid #ccc; border-radius: 4px; font-size: 14px; font-family: inherit; resize: vertical;';

  if (options.readonly) {
    textarea.readOnly = true;
    textarea.style.background = '#f5f5f5';
  }

  textarea.addEventListener('input', (e) => {
    onChange(e.target.value);
  });

  return textarea;
}

